from typing import List


# This function will validate the input expression using regex pattern. The regex pattern used is very simple and doesn't cover all possible cases.
# For a real-world application, you should consider a more complex validation or use an existing library that can safely evaluate expressions.

def is_valid_expression(expr: str) -> bool:
    # disallowed characters
    disallowed_chars = re.compile(r'[^a-zA-Z0-9.\(\)\-\+\*\/\[\]{};\'"\<\>\s]')
    return not bool(disallowed_chars.search(expr))


def evaluate_expression_safe(expr: str, allowed_functions: List[str]) -> str:
    # Make sure the expression only includes valid functions
    disallowed_function_calls = re.compile(f'({|})\\b'.join(allowed_functions))

    if not disallowed_function_calls.search(expr):
        try:
            return eval(expr)
        except Exception as e:
            return f"Error: {e}"
    else:
        raise ValueError("Invalid function calls in expression")


