def is_valid_redis_command(command: str) -> bool:
    allowed_commands = ["PING", "EVAL", "EXEC", "multi", "discard"]
    return command in allowed_commands

def restore_from_cache(redis_conn, key):
    if not isinstance(key, str):
        raise ValueError("Key must be a string.")

    command = f"GET {key}"
    if is_valid_redis_command(command):
        redis_conn.execute_command(*command)
        return pickle.loads(redis_conn.get(key))
    else:
        raise ValueError(f"Invalid Redis command: {command}")

