def is_valid_sql(s: str) -> bool:
    s = s.replace('\n', '')
    pat = r"(?:;|\b(SELECT|INSERT|UPDATE|DELETE|CREATE|DROP|TRUNCATE)\b|\b(--|#)\b|--.*\n)"
    if not bool(re.search(pat, s)):
        return True
    else:
        return False

