import urllib.request
from urllib.parse import urlparse
from django.http import HttpResponse, HttpResponseBadRequest

def proxy_image(request):
    image_url = request.GET.get('src', '')
    parsed = urlparse(image_url)
    if parsed.scheme not in ('http', 'https'):
        return HttpResponseBadRequest('Only http/https allowed')
    if parsed.hostname in ('localhost', '127.0.0.1', '::1') or \
       (parsed.hostname or '').startswith('169.254.'):
        return HttpResponseBadRequest('Internal addresses not allowed')
    with urllib.request.urlopen(image_url, timeout=5) as response:
        data = response.read(16 * 1024)  # limit response size
    return HttpResponse(data, content_type='image/jpeg')

